osition: relative;\n}\n\n.special-battle-unlock {\n  position: absolute;\n  top: 0;\n  right: 0;\n  width: 20px;\n  height: 20px;\n  border: none;\n  background: transparent;\n  opacity: 0.08;\n  cursor: pointer;\n  transition: opacity 0.2s;\n}\n\n.special-battle-unlock:hover {\n  opacity: 0.2;\n}\n\n.gold-card {\n  display: flex;\n  align-items: center;\n  gap: 14px;\n  padding: 16px 20px;\n  background: linear-gradient(135deg, rgba(251, 191, 36, 0.25), rgba(251, 191, 36, 0.08));\n  border: 1px solid rgba(251, 191, 36, 0.4);\n  border-radius: 16px;\n  position: relative;\n  backdrop-filter: blur(10px);\n\n  > i {\n    font-size: 28px;\n    color: #fbbf24;\n  }\n\n  .gold-info {\n    display: flex;\n    flex-direction: column;\n    gap: 2px;\n  }\n\n  .gold-label {\n    font-size: 12px;\n    color: rgba(255, 255, 255, 0.6);\n  }\n\n  .gold-value {\n    font-size: 26px;\n    font-weight: 700;\n    color: #fcd34d;\n  }\n}\n\n.shop-detail-view {\n  display: flex;\n  flex-direction: column;\n  gap: 14px;\n}\n\n.detail-page-header {\n  display: flex;\n  align-items: center;\n}\n\n.detail-back-btn {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  padding: 10px 14px;\n  border: 1px solid rgba(255, 255, 255, 0.12);\n  border-radius: 12px;\n  background: rgba(255, 255, 255, 0.05);\n  color: white;\n  cursor: pointer;\n}\n\n.detail-title-block {\n  display: flex;\n  flex-direction: column;\n  gap: 4px;\n}\n\n.detail-page-title {\n  font-size: 18px;\n  font-weight: 700;\n  color: #fff;\n}\n\n.detail-page-subtitle {\n  font-size: 12px;\n  color: rgba(255, 255, 255, 0.6);\n}\n\n.fetish-detail-header {\n  justify-content: space-between;\n}\n\n.fetish-detail-card {\n  max-width: 760px;\n}\n\n.shop-detail-card {\n  display: flex;\n  flex-direction: column;\n  background: linear-gradient(180deg, #1e1e2e, #151520);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 20px;\n  overflow: hidden;\n}\n\n.detail-preview {\n  margin: 16px;\n  margin-bottom: 0;\n}\n\n.shop-detail-body {\n  display: flex;\n  flex-direction: column;\n  gap: 16px;\n}\n\n.detail-price-summary {\n  margin-bottom: 0;\n}\n\n.shop-detail-footer {\n  position: sticky;\n  bottom: 0;\n  background: linear-gradient(180deg, rgba(30, 30, 46, 0.98), rgba(21, 21, 32, 0.98));\n  backdrop-filter: blur(10px);\n}\n\n.category-tabs {\n  display: flex;\n  gap: 8px;\n  margin-bottom: 16px;\n  overflow-x: auto;\n  padding-bottom: 4px;\n\n  &::-webkit-scrollbar {\n    height: 3px;\n  }\n}\n\n.category-tab {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  padding: 10px 16px;\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 10px;\n  color: rgba(255, 255, 255, 0.6);\n  font-size: 13px;\n  font-weight: 500;\n  cursor: pointer;\n  transition: all 0.2s;\n  white-space: nowrap;\n\n  i {\n    font-size: 14px;\n  }\n\n  &:hover {\n    background: rgba(255, 255, 255, 0.08);\n    color: rgba(255, 255, 255, 0.8);\n  }\n\n  &.active {\n    background: linear-gradient(135deg, #667eea, #764ba2);\n    border-color: transparent;\n    color: white;\n  }\n}\n\n.filter-bar {\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  padding: 12px;\n  background: rgba(255, 255, 255, 0.03);\n  border-radius: 12px;\n  margin-bottom: 16px;\n}\n\n.filter-group {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  flex-wrap: wrap;\n}\n\n.filter-label {\n  font-size: 11px;\n  color: rgba(255, 255, 255, 0.5);\n  min-width: 36px;\n}\n\n.filter-options {\n  display: flex;\n  gap: 6px;\n  flex-wrap: wrap;\n}\n\n.filter-btn {\n  padding: 4px 10px;\n  font-size: 11px;\n  background: rgba(255, 255, 255, 0.05);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 6px;\n  color: rgba(255, 255, 255, 0.6);\n  cursor: pointer;\n  transition: all 0.2s;\n\n  &:hover {\n    background: rgba(255, 255, 255, 0.1);\n    color: white;\n  }\n\n  &.active {\n    color: white;\n\n    &.grade-c {\n      background: rgba(156, 1