 126, 234, 0.05));\n  border: 1px solid rgba(102, 126, 234, 0.2);\n  border-radius: 12px;\n\n  .present-avatar {\n    width: 32px;\n    height: 32px;\n    border-radius: 50%;\n    background: rgba(102, 126, 234, 0.3);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    overflow: hidden;\n    cursor: pointer;\n    transition: transform 0.2s ease;\n\n    &:hover {\n      transform: scale(1.1);\n    }\n\n    .avatar-img {\n      width: 100%;\n      height: 100%;\n      object-fit: cover;\n    }\n\n    i,\n    .fallback-icon {\n      font-size: 14px;\n      color: #a5b4fc;\n    }\n  }\n\n  .present-name {\n    font-size: 13px;\n    font-weight: 500;\n    color: white;\n  }\n}\n\n.relationship-list {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.relationship-card {\n  padding: 16px;\n  background: rgba(255, 255, 255, 0.03);\n  border-radius: 16px;\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  position: relative;\n}\n\n.discard-btn {\n  width: 18px;\n  height: 18px;\n  border-radius: 999px;\n  background: rgba(248, 113, 113, 0.9);\n  border: 1px solid rgba(248, 113, 113, 0.9);\n  color: white;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: all 0.2s ease;\n  position: absolute;\n  top: 12px;\n  right: 12px;\n  z-index: 2;\n\n  &:hover {\n    transform: scale(1.08);\n    background: rgba(248, 113, 113, 1);\n  }\n\n  &:active {\n    transform: scale(1);\n  }\n\n  i {\n    font-size: 10px;\n    line-height: 1;\n  }\n}\n\n.rel-header {\n  display: flex;\n  align-items: center;\n  gap: 14px;\n  margin-bottom: 16px;\n}\n\n.rel-avatar {\n  width: 48px;\n  height: 48px;\n  border-radius: 50%;\n  background: linear-gradient(135deg, rgba(102, 126, 234, 0.3), rgba(118, 75, 162, 0.2));\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  overflow: hidden;\n  cursor: pointer;\n  transition: transform 0.2s ease;\n\n  &:hover {\n    transform: scale(1.1);\n  }\n\n  .avatar-img {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n  }\n\n  i,\n  .fallback-icon {\n    font-size: 20px;\n    color: rgba(255, 255, 255, 0.6);\n  }\n}\n\n.rel-info {\n  flex: 1;\n  min-width: 0;\n}\n\n.rel-name {\n  font-size: 16px;\n  font-weight: 600;\n  color: white;\n  margin-bottom: 6px;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.rel-tags {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 6px;\n}\n\n.rel-type {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  padding: 4px 10px;\n  border-radius: 12px;\n  font-size: 11px;\n  font-weight: 500;\n\n  i {\n    font-size: 10px;\n  }\n\n  &.type-stranger {\n    background: rgba(156, 163, 175, 0.15);\n    color: #d1d5db;\n  }\n\n  &.type-classmate {\n    background: rgba(96, 165, 250, 0.15);\n    color: #93c5fd;\n  }\n\n  &.type-friend {\n    background: rgba(52, 211, 153, 0.15);\n    color: #6ee7b7;\n  }\n\n  &.type-lover {\n    background: rgba(244, 114, 182, 0.15);\n    color: #f9a8d4;\n  }\n\n  &.type-master {\n    background: rgba(251, 191, 36, 0.15);\n    color: #fcd34d;\n  }\n\n  &.type-submissive {\n    background: rgba(167, 139, 250, 0.15);\n    color: #c4b5fd;\n  }\n\n  &.type-enemy {\n    background: rgba(248, 113, 113, 0.15);\n    color: #fca5a5;\n  }\n\n  &.type-unknown {\n    background: rgba(156, 163, 175, 0.1);\n    color: rgba(255, 255, 255, 0.4);\n  }\n}\n\n.rel-oath {\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  padding: 4px 10px;\n  border-radius: 12px;\n  font-size: 11px;\n  font-weight: 500;\n\n  i {\n    font-size: 9px;\n  }\n\n  &.oath-none {\n    background: rgba(156, 163, 175, 0.1);\n    color: rgba(255, 255, 255, 0.42);\n  }\n\n  &.oath-dominant {\n    background: rgba(251, 191, 36, 0.16);\n    color: #fcd34d;\n  }\n\n  &.oath-equal {\n    background: rgba(244, 114, 182, 0.16);\n    color: #f9a8d4;\n  }\n\n  &.oath-submissive {\n    background: rgba(167, 139, 250, 0.16);\n    color: #c4b5fd;