/**
 * 规范化对手名称：去除中间点等特殊字符
 * 例如："雪莉·克里姆希尔德" -> "谢尔盖克里姆希尔德"
 * @param name 原始名称
 * @returns 规范化后的名称
 */
export function normalizeEnemyName(name: string): string {
  // 去除中间点（·、・、‧等变体）
  return name.replace(/[·・‧]/g, '');
}

/**
 * 根据对手名称获取静态基础数据（支持包含匹配）
 * @param enemyName 对手名称（可以是全名、部分名称或包含多个角色的复合名称）
 * @returns 敌人静态基础数据，如果不存在则返回null
 */
export function getEnemyBaseDataByName(enemyName: string): EnemyBaseData | null {
  // 预处理：去除名字中的中间点
  const normalizedName = normalizeEnemyName(enemyName);

  // 1. 先尝试精确匹配（对手名刚好是某个数据库全名）
  if (normalizedName in ENEMY_DATABASE) {
    return ENEMY_DATABASE[normalizedName];
  }

  // 2. 先尝试精确别名匹配（避免短名包含匹配误判，如"雪莉"误命中"雪"）
  if (normalizedName in NAME_ALIASES) {
    const fullName = NAME_ALIASES[normalizedName];
    if (fullName in ENEMY_DATABASE) {
      return ENEMY_DATABASE[fullName];
    }
  }

  // 3. 尝试包含匹配：遍历数据库全名，如果对手名包含某个全名，返回该数据
  //    如果包含多个，以第一个为准
  const enemyDbNames = Object.keys(ENEMY_DATABASE).sort((a, b) => b.length - a.length);
  for (const fullName of enemyDbNames) {
    if (normalizedName.includes(fullName)) {
      console.info(
        `[敌人数据库] 包含匹配成功（数据）: "${enemyName}" (规范化: "${normalizedName}") 包含 "${fullName}"`,
      );
      return ENEMY_DATABASE[fullName];
    }
  }

  // 4. 尝试别名包含匹配：遍历别名表，如果对手名包含某个别名，返回对应数据
  //    如果包含多个，以第一个为准
  const enemyAliases = Object.entries(NAME_ALIASES).sort((a, b) => b[0].length - a[0].length);
  for (const [alias, fullName] of enemyAliases) {
    if (normalizedName.includes(alias) && fullName in ENEMY_DATABASE) {
      console.info(
        `[敌人数据库] 别名包含匹配成功（数据）: "${enemyName}" (规范化: "${normalizedName}") 包含别名 "${alias}" -> "${fullName}"`,
      );
      return ENEMY_DATABASE[fullName];
    }
  }

  // 5. 都没匹配到，返回null
  console.warn(`[敌人数据库] 未找到数据匹配: "${enemyName}"`);
  return null;
}

/**
 * 根据对手名称获取完整名称（支持包含匹配）
 * @param enemyName 对手名称（可以是全名、部分名称或包含多个角色的复合名称）
 * @returns 完整名称，如果不存在则返回原名称
 */
export function resolveEnemyName(enemyName: string): string {
  // 预处理：去除名字中的中间点
  const normalizedName = normalizeEnemyName(enemyName);

  // 1. 先尝试精确匹配（对手名刚好是某个数据库全名）
  if (normalizedName in ENEMY_DATABASE) {
    return normalizedName;
  }

  // 2. 先尝试精确别名匹配（避免短名包含匹配误判，如"雪莉"误命中"雪"）
  if (normalizedName in NAME_ALIASES) {
    const fullName = NAME_ALIASES[normalizedName];
    if (fullName in ENEMY_DATABASE) {
      return fullName;
    }
  }

  // 3. 尝试包含匹配：遍历数据库全名，如果对手名包含某个全名，返回该全名
  //    如果包含多个，以第一个为准
  const enemyDbNames = Object.keys(ENEMY_DATABASE).sort((a, b) => b.length - a.length);
  for (const fullName of enemyDbNames) {
    if (normalizedName.includes(fullName)) {
      console.info(`[敌人数据库] 包含匹配成功: "${enemyName}" (规范化: "${normalizedName}") 包含 "${fullName}"`);
      return fullName;
    }
  }

  // 4. 尝试别名包含匹配：遍历别名表，如果对手名包含某个别名，返回对应全名
  //    如果包含多个，以第一个为准
  const enemyAliases = Object.entries(NAME_ALIASES).sort((a, b) => b[0].length - a[0].length);
  for (const [alias, fullName] of enemyAliases) {
    if (normalizedName.includes(alias) && fullName in ENEMY_DATABASE) {
      console.info(
        `[敌人数据库] 别名包含匹配成功: "${enemyName}" (规范化: "${normalizedName}") 包含别名 "${alias}" -> "${fullName}"`,
      );
      return fullName;
    }
  }

  // 5. 都没匹配到，返回原名
  console.warn(`[敌人数据库] 未找到匹配: "${enemyName}"，返回原名`);
  return enemyName;
}

/**
 * 检查是否存在指定名称的敌人数据（支持模糊匹配）
 * @param enemyName 对手名称
 * @returns 是否存在
 */
export function hasEnemyData(enemyName: string): boolean {
  return getEnemyBaseDataByName(enemyName) !== null;
}

