ns: repeat(2, minmax(0, 1fr));\n  gap: 8px;\n}\n\n.sticker-panel {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  gap: 7px;\n}\n\n.sticker-prompt-toggle {\n  position: relative;\n  min-height: 30px;\n  padding: 0 8px;\n  border-radius: 10px;\n  display: flex;\n  align-items: center;\n  gap: 7px;\n  color: rgba(255, 255, 255, 0.76);\n  background: rgba(255, 255, 255, 0.07);\n  font-size: 12px;\n  font-weight: 800;\n\n  input {\n    width: 14px;\n    height: 14px;\n    accent-color: #f59e0b;\n    flex-shrink: 0;\n  }\n\n  span {\n    min-width: 0;\n    flex: 1;\n    overflow: hidden;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n  }\n\n  i {\n    color: rgba(254, 243, 199, 0.78);\n    font-size: 12px;\n    flex-shrink: 0;\n  }\n\n  &::after {\n    content: attr(data-help);\n    position: absolute;\n    left: 0;\n    right: 0;\n    top: calc(100% + 6px);\n    box-sizing: border-box;\n    min-height: 34px;\n    padding: 8px 10px;\n    border: 1px solid rgba(251, 191, 36, 0.24);\n    border-radius: 10px;\n    display: none;\n    align-items: center;\n    color: #fef3c7;\n    background: rgba(15, 23, 42, 0.96);\n    box-shadow: 0 10px 24px rgba(0, 0, 0, 0.28);\n    font-size: 12px;\n    line-height: 1.35;\n    white-space: normal;\n    word-break: normal;\n    overflow-wrap: break-word;\n    z-index: 5;\n  }\n\n  &:hover::after,\n  &:active::after,\n  &:focus-within::after {\n    display: flex;\n  }\n}\n\n.sticker-preview {\n  position: absolute;\n  left: 0;\n  right: 0;\n  bottom: calc(100% + 10px);\n  min-height: 184px;\n  border: 1px solid rgba(251, 191, 36, 0.22);\n  border-radius: 13px;\n  padding: 10px;\n  display: grid;\n  grid-template-rows: minmax(0, 1fr) auto;\n  gap: 6px;\n  background:\n    linear-gradient(155deg, rgba(15, 23, 42, 0.97), rgba(42, 31, 55, 0.9)),\n    rgba(10, 14, 28, 0.94);\n  box-shadow: 0 14px 30px rgba(0, 0, 0, 0.36);\n  pointer-events: none;\n  z-index: 4;\n\n  img {\n    width: 100%;\n    height: 154px;\n    object-fit: contain;\n    display: block;\n  }\n\n  span {\n    min-width: 0;\n    overflow: hidden;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n    color: rgba(255, 255, 255, 0.84);\n    font-size: 12px;\n    font-weight: 800;\n    text-align: center;\n  }\n}\n\n.emoji-option {\n  width: 100%;\n  aspect-ratio: 1;\n  border: 0;\n  border-radius: 11px;\n  display: grid;\n  place-items: center;\n  color: #fff;\n  background: rgba(255, 255, 255, 0.08);\n  font-size: 18px;\n  line-height: 1;\n  transition:\n    background 0.15s,\n    transform 0.15s;\n\n  &:hover {\n    background: rgba(251, 191, 36, 0.18);\n    transform: translateY(-1px);\n  }\n\n  &:active {\n    transform: scale(0.94);\n  }\n}\n\n.sticker-option {\n  width: 100%;\n  aspect-ratio: 1;\n  border: 0;\n  border-radius: 11px;\n  padding: 7px;\n  display: grid;\n  place-items: center;\n  background: rgba(255, 255, 255, 0.08);\n  transition:\n    background 0.15s,\n    transform 0.15s;\n\n  img {\n    width: 100%;\n    height: 100%;\n    object-fit: contain;\n    display: block;\n  }\n\n  &:hover {\n    background: rgba(251, 191, 36, 0.18);\n    transform: translateY(-1px);\n  }\n\n  &:active {\n    transform: scale(0.94);\n  }\n}\n\n.sticker-state {\n  min-height: 78px;\n  grid-column: 1 / -1;\n  border: 0;\n  display: grid;\n  place-items: center;\n  color: rgba(255, 255, 255, 0.68);\n  background: transparent;\n  font-size: 12px;\n  font-weight: 800;\n\n  &.retry {\n    color: #fef3c7;\n  }\n}\n\n.composer-attachment-preview {\n  position: absolute;\n  left: 10px;\n  right: 10px;\n  bottom: calc(100% + 8px);\n  min-height: 58px;\n  max-height: 132px;\n  overflow-y: auto;\n  border: 1px solid rgba(125, 211, 252, 0.24);\n  border-radius: 16px;\n  padding: 8px;\n  display: flex;\n  flex-direction: column;\n  gap: 9px;\n  color: #e0f2fe;\n  background:\n    linear-gradient(155deg, rgba(15, 23, 42, 0.94), rgba(24, 43, 63, 0.84)),\n    rgba(10, 14, 28, 0.9);\n  box-shadow:\n    0 16px 38px rgba(0, 0, 0, 0.34),\n    inset 0 1px 0 rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(16px);\n  z-index: 10;\n}\n\n.composer-attachment-item {\n  min-height: 42px;\n  display: grid;\n  grid-template-columns: 42px minmax(0, 1fr) 30px;\n  align-items: center;\n  gap: 9px;\n\n  img {\n    width: 42px;\n    height: 42px;\n    border-radius: 12px;\n    object-fit: cover;\n    display: block;\n  }\n\n  span {\n    min-width: 0;\n    overflow: hidden;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n    font-size: 12px;\n    font-weight: 750;\n  }\n\n  button {\n    width: 30px;\n    height: 30px;\n    border: 0;\n    border-radius: 10px;\n    display: grid;\n    place-items: center;\n    color: #fff;\n    background: rgba(255, 255, 255, 0.1);\n  }\n}\n\n.composer-attach-toggle,\n.composer-emoji-toggle {\n  width: 38px;\n  height: 38px;\n  border: 0;\n  border-radius: 12px;\n  display: grid;\n  place-items: center;\n  color: rgba(39, 49, 61, 0.72);\n  background: rgba(255, 255, 255, 0.9);\n  font-size: 16px;\n  flex-shrink: 0;\n  box-shadow: inset 0 0 0 1px rgba(33, 49, 59, 0.1);\n  transition:\n    color 0.15s,\n    background 0.15s,\n    transform 0.15s;\n\n  &:disabled {\n    opacity: 0.35;\n  }\n\n  &.active,\n  &:not(:disabled):hover {\n    color: #fff;\n    background: linear-gradient(145deg, #f59e0b, #ec4899);\n    transform: translateY(-1px);\n  }\n}\n\n.composer-attach-toggle {\n  &:not(:disabled):hover {\n    color: #fff;\n    background: linear-gradient(145deg, #0ea5e9, #14b8a6);\n    transform: translateY(-1px);\n  }\n}\n\n.composer-send {\n  width: 38px;\n  height: 38px;\n  border: 0;\n  border-radius: 12px;\n  display: grid;\n  place-items: center;\n  color: #fff;\n  background: linear-gradient(145deg, #6366f1, #8b5cf6);\n  font-size: 14px;\n  flex-shrink: 0;\n  box-shadow:\n    0 4px 14px rgba(99, 102, 241, 0.35),\n    inset 0 1px 0 rgba(255, 255, 255, 0.2);\n  transition:\n    opacity 0.15s,\n    transform 0.15s;\n\n  &:disabled {\n    opacity: 0.35;\n    box-shadow: none;\n  }\n\n  &:not(:disabled):hover {\n    transform: scale(1.06);\n  }\n\n  &:not(:disabled):active {\n    transform: scale(0.95);\n  }\n}\n\n.composer-file-input {\n  display: none;\n}\n\n\n\n/* ═══════════════════════════════════════════════════════\n   Error & Empty States\n   ═══════════════════════════════════════════════════════ */\n.error-row,\n.empty-state {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 8px;\n  font-size: 13px;\n}\n\n.error-row {\n  min-height: 34px;\n  color: #fca5a5;\n  background: rgba(239, 68, 68, 0.15);\n  border-top: 1px solid rgba(239, 68, 68, 0.12);\n  padding: 0 12px;\n  backdrop-filter: blur(6px);\n}\n\n.contact-error {\n  flex-shrink: 0;\n  border: 1px solid rgba(239, 68, 68, 0.14);\n  border-radius: 13px;\n}\n\n.empty-state {\n  color: rgba(240, 236, 255, 0.4);\n  padding: 24px 0;\n}\n\n.chat-empty {\n  height: 100%;\n}\n\n/* ═══════════════════════════════════════════════════════\n   Animations\n   ═══════════════════════════════════════════════════════ */\n@keyframes typing-pulse {\n  0%,\n  80%,\n  100% {\n    opacity: 0.3;\n    transform: translateY(0);\n  }\n\n  40% {\n    opacity: 1;\n    transform: translateY(-3px);\n  }\n}\n\n@keyframes spin {\n  to {\n    transform: rotate(360deg);\n  }\n}\n"],"sourceRoot":""}]);
