font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Microsoft YaHei', sans-serif;\n\n  position: relative;\n  width: 100%;\n  height: 100%;\n  border: 10px solid #202126;\n  border-radius: 46px;\n  overflow: hidden;\n  background:\n    radial-gradient(circle at 50% 38%, rgba(255, 255, 255, 0.22), transparent 30%),\n    linear-gradient(180deg, var(--screen-base), #77d7d3 64%, #82ddd7);\n  box-shadow:\n    inset 0 0 0 1px rgba(255, 255, 255, 0.08),\n    inset 0 0 0 2px rgba(0, 0, 0, 0.18);\n  font-family: var(--phone-font-family);\n}\n\n.theme-midnight {\n  --screen-base: #202741;\n  --screen-accent: #5d6ac6;\n  --screen-accent-strong: #24305d;\n  --glass-bg: rgba(20, 27, 50, 0.64);\n}\n\n.theme-rose {\n  --screen-base: #e89ab6;\n  --screen-accent: #ba6689;\n  --screen-accent-strong: #7f415f;\n  --glass-bg: rgba(132, 63, 91, 0.56);\n}\n\n.theme-glass {\n  --screen-base: #b7c8d8;\n  --screen-accent: #65798b;\n  --screen-accent-strong: #3a4d5f;\n  --glass-bg: rgba(69, 86, 102, 0.5);\n}\n\n.phone-wallpaper {\n  position: absolute;\n  inset: 0;\n  background-size: cover;\n  background-position: center;\n  opacity: var(--phone-wallpaper-opacity);\n  filter: blur(var(--phone-wallpaper-blur));\n  transform: scale(1.04);\n  z-index: 0;\n}\n\n.phone-wallpaper-image {\n  width: 100%;\n  height: 100%;\n  display: block;\n  object-fit: cover;\n  object-position: center;\n}\n\n.phone-tint {\n  position: absolute;\n  inset: 0;\n  background: rgba(7, 18, 28, var(--phone-tint-opacity));\n  pointer-events: none;\n  z-index: 1;\n}\n\n.phone-screen {\n  position: relative;\n  z-index: 3;\n  height: 100%;\n  min-height: 0;\n  padding: 32px 28px 42px;\n  box-sizing: border-box;\n}\n\n.phone-screen-app {\n  padding: 0;\n}\n\n.phone-exit-button {\n  position: absolute;\n  top: 18px;\n  right: 20px;\n  z-index: 8;\n  width: 38px;\n  height: 38px;\n  border: 1px solid rgba(255, 255, 255, 0.22);\n  border-radius: 13px;\n  display: grid;\n  place-items: center;\n  color: rgba(255, 255, 255, 0.92);\n  background: rgba(14, 30, 38, 0.28);\n  box-shadow:\n    0 10px 22px rgba(15, 23, 42, 0.16),\n    inset 0 1px 0 rgba(255, 255, 255, 0.18);\n  cursor: pointer;\n  backdrop-filter: blur(12px);\n  transition:\n    transform 0.16s ease,\n    background 0.16s ease;\n\n  &:hover {\n    transform: translateY(-1px);\n    background: rgba(14, 30, 38, 0.42);\n  }\n}\n\n.home-screen,\n.app-page-shell {\n  height: 100%;\n  min-height: 0;\n}\n\n.home-screen {\n  display: flex;\n  flex-direction: column;\n}\n\n.home-widgets {\n  display: grid;\n  grid-template-columns: repeat(2, minmax(0, 1fr));\n  gap: 18px;\n  margin: 38px 0 38px;\n}\n\n.home-widget {\n  min-width: 0;\n  height: 90px;\n  border: 1px solid var(--glass-border);\n  border-radius: 22px;\n  padding: 14px 12px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  color: #fff;\n  background: var(--glass-bg);\n  box-shadow:\n    0 12px 18px rgba(30, 64, 72, 0.18),\n    inset 0 1px 0 rgba(255, 255, 255, 0.18);\n  cursor: pointer;\n  backdrop-filter: blur(10px);\n  transition:\n    transform 0.18s ease,\n    background 0.18s ease;\n\n  &:hover {\n    transform: translateY(-2px);\n    background: rgba(255, 255, 255, 0.18);\n  }\n}\n\n.widget-main {\n  max-width: 100%;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n  font-size: 28px;\n  line-height: 1.1;\n  font-weight: 700;\n}\n\n.location-widget .widget-main {\n  font-size: 22px;\n}\n\n.widget-sub {\n  max-width: 100%;\n  margin-top: 8px;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n  font-size: 14px;\n  color: rgba(255, 255, 255, 0.78);\n}\n\n.app-grid {\n  display: grid;\n  grid-template-columns: repeat(3, 76px);\n  row-gap: 26px;\n  column-gap: 20px;\n  justify-content: space-between;\n  justify-items: center;\n  align-content: start;\n}\n\n.phone-app,\n.dock-app {\n  width: 76px;\n  min-width: 0;\n  min-height: 88px;\n  border: 0;\n  padding: 0;\n  display: flex;\n  flex: 0 0 auto;\n  flex-direction: column;\n  align-items: center;\n  justify-content: flex-start;\n  gap: 8px;\n  color: #fff;\n  background: transparent;\n  appearance: none;\n  -webkit-appearance: none;\n  cursor: pointer;\n  text-shadow: 0 2px 8px rgba(0, 0, 0, 0.28);\n  transition: transform 0.16s ease;\n\n  &:hover {\n    transform: translateY(-2px);\n  }\n\n  &:active {\n    transform: scale(0.96);\n  }\n}\n\n.app-icon {\n  position: relative;\n  width: 58px;\n  height: 58px;\n  min-width: 58px;\n  max-width: 58px;\n  min-height: 58px;\n  max-height: 58px;\n  flex: 0 0 58px;\n  aspect-ratio: 1 / 1;\n  box-sizing: border-box;\n  border: 1px solid rgba(255, 255, 255, 0.16);\n  border-radius: 16px;\n  overflow: hidden;\n  display: grid;\n  place-items: center;\n  color: rgba(255, 255, 255, 0.94);\n  background: rgba(80, 133, 136, 0.78);\n  box-shadow:\n    0 10px 18px rgba(28, 64, 74, 0.24),\n    inset 0 1px 0 rgba(255, 255, 255, 0.2);\n  transition:\n    border-radius 0.18s ease,\n    clip-path 0.18s ease,\n    filter 0.18s ease,\n    box-shadow 0.18s ease,\n    transform 0.18s ease;\n\n  &::before {\n    content: '';\n    position: absolute;\n    inset: 0;\n    pointer-events: none;\n  }\n\n  &::after {\n    content: '';\n    position: absolute;\n    inset: 0;\n    background: linear-gradient(145deg, rgba(255, 255, 255, 0.32), transparent 42%, rgba(0, 0, 0, 0.14));\n    pointer-events: none;\n  }\n\n  i {\n    position: relative;\n    z-index: 1;\n    font-size: 25px;\n    line-height: 1;\n  }\n}\n\n.script-update-dot {\n  position: absolute;\n  top: 5px;\n  right: 5px;\n  z-index: 4;\n  width: 10px;\n  height: 10px;\n  border: 2px solid rgba(255, 255, 255, 0.92);\n  border-radius: 999px;\n  background: #ff3b30;\n  box-shadow:\n    0 0 0 1px rgba(125, 18, 18, 0.22),\n    0 0 10px rgba(255, 59, 48, 0.72);\n  pointer-events: none;\n  box-sizing: border-box;\n}\n\n.app-label {\n  width: 76px;\n  min-height: 17px;\n  overflow: hidden;\n  text-align